B.J5=new A.aB("The aircraft requires GPU connection as the APU is unserviceable.","APU ar\u0131zal\u0131 oldu\u011fundan u\xe7ak yer g\xfc\xe7 \xfcnitesi ba\u011flant\u0131s\u0131 gerektiriyor.","GPU connection")
