B.OR=new A.S(B.a6,"Approach phraseology is highly structured","The approach and landing phase uses the most regulated phraseology in aviation. Precise language is essential because misunderstandings during approach have caused accidents.\n\nFill-in-the-blank questions in this area test knowledge of exact ICAO phrases and their correct prepositions and keywords.",null,null,null)
B.P1=new A.S(B.B,"\ud83d\udeec Approach Clearance Phrases",'"Cleared **ILS approach** runway 36R"\n"Cleared **visual approach** runway 18L"\n"Cleared **RNAV(GPS) approach** runway 05"\n"**Descend** on the glide path"\n"**Established** on localizer / on the ILS"\n"**Report** outer marker / FAF / visual"\n"**Missed approach** \u2014 go around, climb to 4000 feet"\n"**Wind check**: 270/15, **cleared to land**"',null,null,null)
B.NF=new A.S(B.B,"\ud83d\udccf Approach Distance & Height","**Final approach** \u2014 last straight segment to runway\n**Short final** \u2014 within 4nm of runway threshold\n**Glide slope** \u2014 vertical guidance component of ILS\n**Localizer** \u2014 horizontal guidance component of ILS\n**Decision altitude (DA)** \u2014 height at which missed approach must be initiated if no visual contact\n**Minimum Descent Altitude (MDA)** \u2014 minimum height in non-precision approach\n**Touch-down zone** \u2014 first 3,000 feet of runway used for landing",null,null,null)
B.Jw=new A.aB("THY123, report established on the ILS runway 36R.","THY123, pist 36R ILS'inde kuruldu\u011funuzda bildirin.","established")
B.Jo=new A.aB("Continue approach, wind 280 degrees 12 knots, cleared to land.","Yakla\u015fmaya devam edin, r\xfczgar 280 derece 12 knot, ini\u015fe yetkilendirildiniz.","cleared to land")
B.Jn=new A.aB("Go around, I say again, go around \u2014 obstructions on runway.","T\u0131rman\u0131\u015f yap\u0131n, tekrar ediyorum, t\u0131rman\u0131\u015f yap\u0131n \u2014 piste engel.","Go around")
