B.a0U=new A.a4(-231,B.ax,781,"Before performing any engine shutdown action, the crew should \u2026\u2026\u2026\u2026 the affected engine.",B.Qf,2,B.z,null,null,null)
B.TT=s(["activate","fire","discharge","release"],t.s)
