B.VK=s(["stall","surge","failure","seizure"],t.s)
B.a_S=new A.a4(-233,B.ax,783,"A compressor stall in a jet engine is also known as a compressor \u2026\u2026\u2026\u2026.",B.VK,1,B.aQ,null,null,null)
