B.Nr=new A.S(B.a6,"Advanced texts use complex grammatical structures","Aviation documents, accident reports, and ICAO publications use complex sentence structures that combine multiple clauses. At the advanced level, you must handle these accurately in both comprehension and production questions.",null,null,null)
B.Nb=new A.S(B.B,"Relative Clauses",'**Defining** (no commas): identifies which one\n\u2192 "The component **that failed** was the hydraulic pump."\n\n**Non-defining** (with commas): adds extra information\n\u2192 "The hydraulic pump, **which had just been serviced**, failed."\n\n**Reduced relative clause** (participle phrase):\n\u2192 "The pilot **flying the aircraft** reported vibration." (= who was flying)\n\u2192 "The component **installed last week** is defective." (= that was installed)',null,null,null)
B.Pz=new A.S(B.B,"Participial Phrases & Inversion",'**Present participle** (active, simultaneous):\n\u2192 "**Having received** the clearance, the crew began the takeoff roll."\n\n**Past participle** (passive, completed first):\n\u2192 "**Notified by ATC**, the pilot diverted to the alternate."\n\n**Negative inversion** (formal/reports):\n\u2192 "**Under no circumstances should** the aircraft depart without a clearance."\n\u2192 "**Not until the checks were completed** did the captain approve departure."',null,null,null)
B.K7=new A.aB("The maintenance technician, having completed all required inspections, signed the aircraft log.","Bak\u0131m teknisyeni, gerekli t\xfcm denetimleri tamamlad\u0131ktan sonra u\xe7ak k\xfct\xfc\u011f\xfcn\xfc imzalad\u0131.","having completed")
B.K5=new A.aB("Under no circumstances should flight crew members operate the aircraft beyond approved limits.","U\xe7u\u015f ekibi \xfcyeleri hi\xe7bir ko\u015fulda u\xe7a\u011f\u0131 onaylanan limitler d\u0131\u015f\u0131nda kullanmamal\u0131d\u0131r.","Under no circumstances should")
B.Q6=s([B.K7,B.K5],t.l)
B.Os=new A.S(B.a7,"Complex Structure Examples",null,B.Q6,null,null)
B.PE=new A.S(B.a8,"\u2708\ufe0f Exam Tip",'Inversion signals in exam questions:\n\u2022 "Under no circumstances\u2026" \u2192 should/must come before subject\n\u2022 "Not until\u2026" \u2192 did/could comes before subject in main clause\n\u2022 "Only after\u2026" \u2192 inversion in main clause\n\nParticiple phrases \u2014 check the subject:\n\u2022 "**Having landed**, the aircraft was directed to the gate." \u2713 (aircraft landed)\n\u2022 "**Having landed**, the gate was assigned." \u2717 (gate didn\'t land \u2014 dangling participle)',null,null,null)
