B.Vd=s(["In accordance with SOPs","Violating or not following SOPs","Similar to SOPs in other companies","An improvement over SOPs"],t.s)
B.a0I=new A.a4(-301,B.b_,461,'"Contrary to standard operating procedures" means:',B.Vd,1,B.z,null,null,null)
B.V6=s(["The main cause was crew rest","Crew rest was one element that made the accident more likely","Crew rest alone caused the accident","The crew rested adequately"],t.s)
B.a0D=new A.a4(-302,B.b_,462,'"A contributing factor was the inadequate crew rest period." This means:',B.V6,1,B.z,null,null,null)
B.RW=s(["It is confirmed that","There was not enough evidence to establish","It is unlikely that","The investigation did not examine"],t.s)
B.a0n=new A.a4(-303,B.b_,463,'"It could not be determined whether\u2026" in a report means:',B.RW,1,B.aQ,null,null,null)
